mapper.select:
SELECT 
  FROM apt_contact_attempt c
 WHERE c.tenant_id = #{tenantId} AND c.contact_attempt_id = #{contactAttemptId}

mapper.insert:
INSERT INTO apt_contact_attempt (
    contact_attempt_id, tenant_id, project_id, work_order_id, task_id, channel,
    contacted_party_ref, started_at, ended_at, result_code, note, next_contact_at,
    recording_ref, actor_id, created_at
) VALUES (
    #{contactAttemptId}, #{tenantId}, #{projectId}, #{workOrderId}, #{taskId}, #{channel},
    #{contactedPartyRef}, #{startedAt}, #{endedAt}, #{resultCode}, #{note}, #{nextContactAt},
    #{recordingRef}, #{actorId}, #{createdAt}
)

INSERT INTO apt_contact_attempt_command_result (
    tenant_id, operation_type, idempotency_key, contact_attempt_id
) VALUES (#{tenantId}, #{operationType}, #{idempotencyKey}, #{contactAttemptId})

mapper.select:
SELECT 
  FROM apt_contact_attempt_command_result r
  JOIN apt_contact_attempt c ON c.contact_attempt_id = r.contact_attempt_id
 WHERE r.tenant_id = #{tenantId} AND r.operation_type = #{operationType}
   AND r.idempotency_key = #{idempotencyKey}

mapper.insert:
INSERT INTO apt_appointment (
    appointment_id, tenant_id, project_id, work_order_id, task_id,
    appointment_type, status, current_revision_id, current_revision_no,
    assigned_network_id, technician_id, aggregate_version, created_by, created_at
) VALUES (
    #{appointmentId}, #{tenantId}, #{projectId}, #{workOrderId}, #{taskId},
    #{appointmentType}, #{status}, #{currentRevisionId}, #{currentRevisionNo},
    #{assignedNetworkId}, #{technicianId}, #{aggregateVersion}, #{createdBy}, #{createdAt}
)

mapper.update:
UPDATE apt_appointment
   SET status = #{newStatus}, current_revision_id = #{newRevisionId},
       current_revision_no = #{newRevisionNo}, aggregate_version = aggregate_version + 1
 WHERE tenant_id = #{tenantId} AND appointment_id = #{appointmentId}
   AND status = #{expectedStatus} AND aggregate_version = #{expectedVersion}

UPDATE apt_appointment
   SET status = #{newStatus}, aggregate_version = aggregate_version + 1
 WHERE tenant_id = #{tenantId} AND appointment_id = #{appointmentId}
   AND status = #{expectedStatus} AND aggregate_version = #{expectedVersion}

